async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    const storeInfo = await browser.extractComponent<{ name: string; subtitle?: string; linkSelector?: string; zipCode?: string }>(
        {
            typeName: 'StoreInfo',
            schema: '{ name: string; subtitle?: string; linkSelector?: string; zipCode?: string; }'
        },
        'store locator'
    );
    if (storeInfo && storeInfo.linkSelector) {
        await browser.click(storeInfo.linkSelector);
        await browser.awaitPageLoad();
    }
    const storesList = await browser.extractComponent<{ stores: { name: string; subtitle?: string; linkSelector: string }[] }>(
        {
            typeName: 'NearbyStoresList',
            schema: '{ stores: { name: string; subtitle?: string; linkSelector: string; }[]; }'
        }
    );
    if (storesList && storesList.stores && storesList.stores.length > 0) {
        return { success: true, message: 'Found ' + storesList.stores.length + ' nearby stores', data: storesList };
    }
    return { success: true, message: 'Store locator opened', data: storeInfo };
}
